+                    unsafe { libc::malloc(name_cstr.as_bytes_with_nul().len()) as *mut c_char };
+                if !name_ptr.is_null() {
+                    unsafe {
+                        std::ptr::copy_nonoverlapping(
+                            name_cstr.as_ptr(),
+                            name_ptr,
+                            name_cstr.as_bytes_with_nul().len(),
+                        );
+                    };
+                }
