+                unsafe {
+                    (*node).ifa_name = name_ptr;
+                    (*node).ifa_flags = if_flags;
+                    (*node).ifa_addr = alloc_sockaddr(amsg.ifa_family, addr_bytes);
+                    (*node).ifa_netmask = alloc_netmask(amsg.ifa_family, amsg.ifa_prefixlen);
